@spec gm_metadata_propagate_spec  src=tests/specs/gm_metadata_propagate_spec.lua  loc=44  sha=f8aa484  cases=1
@exercises groupManager (gm)
@surface   gm:markGroup, gm:newInstance

# Intent
  The group<->instance duals copy the event's full payload, not a
  closed allowlist: any persisted metadata field (rpb, and arbitrary
  unknown keys mm round-trips) survives a duplicate. The mirror image:
  regenerated/derived keys (loc, sampleShadowed, fake) must NOT enter
  the shared group template, or they leak into every sibling.

# Helpers
  @fn rect()  @ 10-11

# Cases
  @case 'a duplicated note carries rpb and arbitrary metadata; derived keys do not leak'  [pure]  @ 15-42

# Uses (outbound edges)
  @use call gm:markGroup  @ 26
  @use call gm:newInstance  @ 28

# Fields (r read / w write incl. constructor keys)
  @field r add  @ 30
  @field w chan  @ 21,28
  @field w chanLo  @ 10
  @field r derived  @ 41
  @field w derived  @ 24
  @field w ds  @ 19
  @field w dur  @ 10
  @field w endppq  @ 22
  @field w endppqL  @ 22
  @field w evType  @ 21
  @field r foo  @ 37
  @field w foo  @ 23
  @field w lane  @ 21
  @field r loc  @ 38
